css:
.loader {
  color: var(--loader-color, #0284c7);
  display: inline-grid;
}
.loader:before,
.loader:after {
  content: "";
  grid-area: 1/1;
  height: 27px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  -webkit-mask: repeating-linear-gradient(90deg,currentColor 0 10%,#0000 0 20%);
  clip-path: inset(0 100% 0 0);
  animation: l16 1.5s infinite steps(6,jump-none);
}
.loader:after {
  -webkit-mask: repeating-linear-gradient(90deg,#0000 0 10%,currentColor 0 20%);
  animation-delay: -.75s;
}
@keyframes l16{
  50%,100% {clip-path: inset(0)}
}
